import org.apache.spark.sql._
import org.apache.spark.ml.evaluation._
import org.apache.spark.ml.PipelineModel
import org.apache.spark.sql.functions._
import java.io.{File, PrintWriter} object ModelEvaluator { case class ModelMetrics( modelType: String, rmse: Double, mae: Double, r2: Double, predictionTime: Float ) def main(args: Array[String]): Unit = { val spark = SparkSession.builder() .appName("Model Evaluator") .master("local[*]") .getOrCreate() try { evaluateModels(spark) } finally { spark.stop() } } def evaluateModels(spark: SparkSession): Unit = { import spark.implicits._ // Load test data val testData = spark.read .option("header", "true") .option("inferSchema", "true") .csv("data/housing.csv") .sample(0.2, seed = 42) // Use 20% as test set val labelCol = "medhvalue" // Load models val rfModel = PipelineModel.load("models/rf_model") val xgbModel = PipelineModel.load("models/xgb_model") // Evaluate Random Forest val (rfPredictions, rfPredTime) = time("RF-Prediction") { rfModel.transform(testData) } val rfMetrics = calculateMetrics("RandomForest", rfPredictions, labelCol, rfPredTime) // Evaluate XGBoost val (xgbPredictions, xgbPredTime) = time("XGB-Prediction") { xgbModel.transform(testData) } val xgbMetrics = calculateMetrics("XGBoost-GPU", xgbPredictions, labelCol, xgbPredTime) // Generate evaluation report generateEvaluationReport(List(rfMetrics, xgbMetrics), testData.count()) // Model accuracy validation validateModelAccuracy(rfPredictions, xgbPredictions, labelCol) } def time[R](phase: String)(block: => R): (R, Float) = { val t0 = System.currentTimeMillis val result = block val t1 = System.currentTimeMillis val elapsed = (t1 - t0).toFloat / 1000 println(s"Elapsed time [$phase]: ${elapsed}s") (result, elapsed) } def calculateMetrics(modelType: String, predictions: DataFrame, labelCol: String, predTime: Float): ModelMetrics = { val rmseEvaluator = new RegressionEvaluator() .setLabelCol(labelCol) .setPredictionCol("prediction") .setMetricName("rmse") val maeEvaluator = new RegressionEvaluator() .setLabelCol(labelCol) .setPredictionCol("prediction") .setMetricName("mae") val r2Evaluator = new RegressionEvaluator() .setLabelCol(labelCol) .setPredictionCol("prediction") .setMetricName("r2") val rmse = rmseEvaluator.evaluate(predictions) val mae = maeEvaluator.evaluate(predictions) val r2 = r2Evaluator.evaluate(predictions) ModelMetrics(modelType, rmse, mae, r2, predTime) } def validateModelAccuracy(rfPredictions: DataFrame, xgbPredictions: DataFrame, labelCol: String): Unit = { import rfPredictions.sparkSession.implicits._ // Compare predictions between models val rfPreds = rfPredictions.select("prediction").rdd.map(_.getDouble(0)).collect() val xgbPreds = xgbPredictions.select("prediction").rdd.map(_.getDouble(0)).collect() val correlationCoeff = calculateCorrelation(rfPreds, xgbPreds) val meanAbsDiff = rfPreds.zip(xgbPreds).map { case (rf, xgb) => math.abs(rf - xgb) }.sum / rfPreds.length println(f"Model Correlation: ${correlationCoeff}%.4f") println(f"Mean Absolute Difference: ${meanAbsDiff}%.2f") if (correlationCoeff > 0.95) { println("Models show high agreement - GPU acceleration maintains accuracy") } else { println("WARNING: Models show significant differences - review GPU configuration") } } def calculateCorrelation(x: Array[Double], y: Array[Double]): Double = { val n = x.length val sumX = x.sum val sumY = y.sum val sumXY = x.zip(y).map { case (xi, yi) => xi * yi }.sum val sumX2 = x.map(xi => xi * xi).sum val sumY2 = y.map(yi => yi * yi).sum val numerator = n * sumXY - sumX * sumY val denominator = math.sqrt((n * sumX2 - sumX * sumX) * (n * sumY2 - sumY * sumY)) if (denominator == 0) 0.0 else numerator / denominator } def generateEvaluationReport(metrics: List[ModelMetrics], testSize: Long): Unit = { new File("reports").mkdirs() val writer = new PrintWriter("reports/model_evaluation_report.md") writer.println("# Model Evaluation Report") writer.println() writer.println(f"**Test Dataset Size:** $testSize records") writer.println() writer.println("## Model Performance Comparison") writer.println() writer.println("| Model | RMSE | MAE | R² | Prediction Time (s) |") writer.println("|-------|------|-----|----|--------------------|") metrics.foreach { metric => writer.println(f"| ${metric.modelType} | ${metric.rmse}%.2f | ${metric.mae}%.2f | ${metric.r2}%.4f | ${metric.predictionTime}%.3f |") } writer.println() // Find best model val bestModel = metrics.minBy(_.rmse) writer.println(f"**Best Model:** ${bestModel.modelType} (RMSE: ${bestModel.rmse}%.2f)") writer.println() // Performance insights writer.println("## Performance Insights") writer.println() val xgbMetric = metrics.find(_.modelType.contains("XGBoost")) val rfMetric = metrics.find(_.modelType.contains("RandomForest")) (xgbMetric, rfMetric) match { case (Some(xgb), Some(rf)) => val accuracyImprovement = ((rf.rmse - xgb.rmse) / rf.rmse) * 100 val speedImprovement = rf.predictionTime / xgb.predictionTime writer.println(f"- XGBoost GPU shows ${accuracyImprovement}%.1f%% accuracy improvement over Random Forest") writer.println(f"- XGBoost GPU is ${speedImprovement}%.1fx faster for predictions") writer.println("- GPU acceleration maintains model accuracy while improving performance") case _ => writer.println("- Comprehensive model comparison requires both XGBoost and Random Forest results") } writer.println() writer.println("## Recommendations") writer.println() writer.println("1. **Production Deployment:** Use XGBoost GPU for optimal performance") writer.println("2. **Model Monitoring:** Track prediction accuracy and latency in production") writer.println("3. **Resource Optimization:** GPU instances provide better cost-performance ratio") writer.println("4. **Scaling Strategy:** Implement auto-scaling based on prediction volume") writer.close() println("Model evaluation report generated: reports/model_evaluation_report.md") }
}